package org.eclipse.rdf4j.workbench.exceptions;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

class ExceptionCoverageTest {

	@Test
	void badRequestExceptionStoresMessage() {
		BadRequestException exception = new BadRequestException("broken request");

		assertThat(exception).hasMessage("broken request");
	}

	@Test
	void badRequestExceptionStoresRootCause() {
		IllegalStateException rootCause = new IllegalStateException("root");

		BadRequestException exception = new BadRequestException("broken request", rootCause);

		assertThat(exception).hasMessage("broken request");
		assertThat(exception.getCause()).isSameAs(rootCause);
	}

	@Test
	void missingInitParameterExceptionFormatsMessage() {
		MissingInitParameterException exception = new MissingInitParameterException("server");

		assertThat(exception).hasMessage("Missing parameter: server");
	}
}
